module RefModule(
  input clk,
  input [2:0] addr1,
  input [2:0] addr2,
  input [7:0] data_in,
  input write_en,
  output reg [7:0] data_out1,
  output reg [7:0] data_out2
);reg [7:0] unused_regs [0:7];

  always @(*) begin
    // Read operations
    data_out1 = unused_regs[addr1];
    data_out2 = unused_regs[addr2];
  end

  always @(posedge clk) begin
    // Write operation
    if (write_en) begin
      unused_regs[addr1] <= data_in;
    end
  end

endmodule
